/// Application error type
#[derive(Debug, thiserror::Error)]
pub enum UserError {
    #[error("Not found: {0}")]
    NotFound(String),
    #[error("Validation error: {0}")]
    Validation(String),
    #[error("Database error: {0}")]
    Database(String),
    #[error("Internal error: {0}")]
    Internal(String),
    // Domain-specific errors from hook rules
    #[error("Username must be 3-50 characters, alphanumeric with underscore/hyphen: {0}")]
    InvalidUsernameFormat(String),
    #[error("Email is already registered: {0}")]
    EmailAlreadyExists(String),
    #[error("Username is already taken: {0}")]
    UsernameAlreadyExists(String),
    #[error("Password must be at least 12 characters with uppercase, lowercase, digit, and special character: {0}")]
    WeakPassword(String),
    #[error("Account is temporarily locked. Try again later.: {0}")]
    AccountLocked(String),
    #[error("Too many failed login attempts. Account locked for 5 minutes.: {0}")]
    MaxAttemptsExceeded(String),
}

impl From<ServiceError> for UserError {
    fn from(err: ServiceError) -> Self {
        match err {
            ServiceError::NotFound => Self::NotFound(err.to_string()),
            ServiceError::Validation(ref msg) => Self::Validation(msg.clone()),
            ServiceError::AlreadyExists(ref msg) => Self::Validation(msg.clone()),
            ServiceError::Repository(ref e) => Self::Database(e.to_string()),
            ServiceError::Internal(ref msg) => Self::Internal(msg.clone()),
        }
    }
}

impl axum::response::IntoResponse for UserError {
    fn into_response(self) -> axum::response::Response {
        use axum::http::StatusCode;
        use axum::Json;

        let (status, code) = match &self {
            Self::NotFound(_) => (StatusCode::NOT_FOUND, "USER_NOT_FOUND"),
            Self::Validation(_) => (StatusCode::BAD_REQUEST, "USER_VALIDATION_ERROR"),
            Self::Database(_) => (StatusCode::INTERNAL_SERVER_ERROR, "USER_DATABASE_ERROR"),
            Self::Internal(_) => (StatusCode::INTERNAL_SERVER_ERROR, "USER_INTERNAL_ERROR"),
            Self::InvalidUsernameFormat(_) => (StatusCode::UNPROCESSABLE_ENTITY, "USER_INVALID_USERNAME_FORMAT"),
            Self::EmailAlreadyExists(_) => (StatusCode::UNPROCESSABLE_ENTITY, "USER_EMAIL_ALREADY_EXISTS"),
            Self::UsernameAlreadyExists(_) => (StatusCode::UNPROCESSABLE_ENTITY, "USER_USERNAME_ALREADY_EXISTS"),
            Self::WeakPassword(_) => (StatusCode::UNPROCESSABLE_ENTITY, "USER_WEAK_PASSWORD"),
            Self::AccountLocked(_) => (StatusCode::UNPROCESSABLE_ENTITY, "USER_ACCOUNT_LOCKED"),
            Self::MaxAttemptsExceeded(_) => (StatusCode::UNPROCESSABLE_ENTITY, "USER_MAX_ATTEMPTS_EXCEEDED"),
        };

        let body = serde_json::json!({
            "success": false,
            "error": code,
            "message": self.to_string(),
        });

        (status, Json(body)).into_response()
    }
}

