/// Create Axum router with all 16 Backbone endpoints for User.
///
/// # Routes
///
/// | Method | Path | Description |
/// |--------|------|-------------|
/// | GET | /users | List with pagination |
/// | POST | /users | Create new |
/// | GET | /users/:id | Get by ID |
/// | PUT | /users/:id | Full update |
/// | PATCH | /users/:id | Partial update |
/// | DELETE | /users/:id | Soft delete |
/// | POST | /users/bulk | Bulk create |
/// | POST | /users/upsert | Upsert |
/// | GET | /users/trash | List deleted |
/// | POST | /users/:id/restore | Restore |
/// | DELETE | /users/empty | Empty trash |
/// | GET | /users/:id/deleted | Get deleted by ID |
/// | DELETE | /users/trash/:id | Permanent delete from trash |
/// | GET | /users/count | Count active entities |
/// | GET | /users/trash/count | Count deleted entities |
///
/// # Example
///
/// ```text
/// let service = Arc::new(UserService::with_repository(repository));
/// let router = create_user_routes(service);
/// ```
pub fn create_user_routes(service: Arc<UserService>) -> Router {
    BackboneCrudHandler::<UserService, User, CreateUserDto, UpdateUserDto, UserResponseDto>::routes(
        service,
        "/users",
    )
}

/// Create authenticated routes with auth middleware.
///
/// Requires the `auth` feature flag. The `AuthMiddleware` implementation
/// is responsible for extracting and validating tokens, then providing
/// an `AuthContext` via request extensions.
#[cfg(feature = "auth")]
pub fn create_protected_user_routes<A: AuthMiddleware + 'static>(
    service: Arc<UserService>,
    auth: Arc<A>,
) -> Router {
    use axum::middleware;
    use axum::response::IntoResponse;

    let auth_layer = auth.clone();
    create_user_routes(service)
        .layer(middleware::from_fn(move |mut req: axum::extract::Request, next: axum::middleware::Next| {
            let auth = auth_layer.clone();
            async move {
                match auth.authenticate(&req).await {
                    Ok(ctx) => {
                        req.extensions_mut().insert(ctx);
                        next.run(req).await
                    }
                    Err(_) => {
                        (axum::http::StatusCode::UNAUTHORIZED,
                         axum::Json(serde_json::json!({
                             "success": false,
                             "error": "unauthorized",
                             "message": "Authentication required"
                         }))
                        ).into_response()
                    }
                }
            }
        }))
}

