/// Create routes for state transitions.
pub fn create_user_transition_routes(service: Arc<UserService>) -> Router {
    use axum::routing::post;

    Router::new()
        .route("/users/:id/transitions/verify", post(verify_transition))
        .route("/users/:id/transitions/activate", post(activate_transition))
        .route("/users/:id/transitions/deactivate", post(deactivate_transition))
        .route("/users/:id/transitions/reactivate", post(reactivate_transition))
        .route("/users/:id/transitions/suspend", post(suspend_transition))
        .with_state(service)
}

